    public void write()
    {
        next write();

        PurchReqLine  newPurchReqLine;

        PurchReqLine  purchReqLine  = this.cursor();
        PurchReqTable purchReqTable = PurchReqTable::findPurchReqId(purchReqLine.purchReqId());

        if(purchReqLine.LineNum == 1 &&
           purchReqTable.UBSRecurringServicePurchase &&
           purchReqLine.UBSAutomaticReceptionDate == dateNull() &&
           this.checkDuplicationaValidity())
        {
            Dialogbutton dialogButtonConfirm = Box::okCancel("@UBS:UBSDuplicationPRLine",DialogButton::Ok);

            if(dialogButtonConfirm == Dialogbutton::Ok)
            {
                TransDate startDate = dateStartMth(purchReqTable.UBSStartingMonth);
                
                ttsbegin;
                purchReqLine.UBSAutomaticReceptionDate = dateStartMth(purchReqTable.UBSStartingMonth);
                purchReqLine.update();

                for(int i = 1; i < purchReqTable.UBSPeriodNumber; i++)
                {
                    startDate = nextMth(startDate);
                    newPurchReqLine.data(purchReqLine);
                    newPurchReqLine.LineNum        = i+1;
                    newPurchReqLine.SequenceNumber = any2int(i+1);
                    newPurchReqLine.RecId          = 0;
                    newPurchReqLine.UBSAutomaticReceptionDate = startDate;
                    newPurchReqLine.insert();
                }
                ttscommit;

                newPurchReqLine.clear();

                ttsbegin;
                update_recordset newPurchReqLine
                    setting PurchPrice = purchReqLine.PurchPrice,
                            LineAmount = purchReqLine.LineAmount,
                            VendAccount = purchReqLine.VendAccount
                    where newPurchReqLine.PurchReqTable == purchReqLine.PurchReqTable &&
                          newPurchReqLine.LineNum != 1;

                ttscommit;
            }
            this.research();
        }
    }

    private boolean checkDuplicationaValidity()
    {
        boolean ret;
        PurchReqLine  purchReqLine  = this.cursor();

        if(purchReqLine.ItemId && purchReqLine.VendAccount && purchReqLine.PurchPrice && purchReqLine.PurchQty)
        {
            return true;
        }
        return ret;
    }
